				<FichePlat 
				    title="Spaghetti Carbonara"
				    description="Un plat italien classique à base de pâtes, d'œufs, de fromage et de pancetta."
				    image="https://example.com/spaghetti-carbonara.jpg"
				    ingredients={["200g de spaghetti", "100g de pancetta", "2 œufs", "50g de parmesan", "Sel", "Poivre"]}
				/>
			</body>
		</div>
	);
}

export default App;
